INSERT INTO public.blog_posts (
  slug, title, meta_title, meta_description,
  author_name, author_avatar_url, category, tags,
  reading_time, is_published, is_featured,
  published_at, faq_data, content
) VALUES (
  'que-es-earn-out',
  'Qué es un earn-out en M&A: cómo funciona, cláusulas y ejemplos [2026]',
  'Qué es un earn-out en M&A: cómo funciona, cláusulas y ejemplos [2026]',
  'El earn-out es un pago variable en la compraventa de empresas vinculado a resultados futuros. Descubre cómo funciona, qué cláusulas incluir, riesgos para comprador y vendedor, y ejemplos prácticos en el mid-market español.',
  'Samuel Navarro',
  'https://fwhqtzkkvnjkazhaficj.supabase.co/storage/v1/object/public/case-studies-images/team/1756718254153_74hs9r.png',
  'M&A',
  ARRAY['earn out', 'earn out que es', 'earn out m&a', 'clausula earn out', 'pago diferido venta empresa', 'earn out ejemplo', 'earn out contrato compraventa', 'earn out significado'],
  12,
  false,
  false,
  NOW(),
  '[
    {"question": "¿Qué porcentaje del precio suele ser earn-out?", "answer": "En el mid-market español y europeo, el earn-out representa típicamente entre el 10% y el 30% del precio total de la operación. Porcentajes superiores al 40% son inusuales y suelen indicar un nivel de incertidumbre muy alto sobre el negocio. Según el CMS European M&A Study 2024, la media se sitúa en torno al 20-25% del precio total."},
    {"question": "¿Es mejor EBITDA o facturación como métrica de earn-out?", "answer": "Depende del contexto. El EBITDA es la métrica más habitual porque refleja la rentabilidad real, pero es más susceptible de manipulación (el comprador puede cargar costes corporativos). La facturación es más transparente y difícil de manipular, pero no refleja la rentabilidad. En empresas en fase de crecimiento (start-ups, scale-ups), la facturación suele ser más apropiada. En empresas maduras, el EBITDA es el estándar."},
    {"question": "¿Puedo negarme a aceptar un earn-out?", "answer": "Sí, el vendedor puede rechazar una estructura con earn-out. Sin embargo, en la práctica, rechazar cualquier componente variable puede significar aceptar un precio al cierre menor o incluso perder al comprador. La clave es negociar las cláusulas del earn-out para proteger tus intereses, no rechazarlo frontalmente si la oferta global es atractiva."},
    {"question": "¿Qué pasa si el comprador no paga el earn-out?", "answer": "Si los objetivos se cumplen y el comprador no paga, el vendedor tiene acción legal para reclamar. Pero litigar es costoso e incierto. Por eso es fundamental negociar garantías de pago: depósito en escrow, aval bancario, garantía de la sociedad matriz del comprador, o cláusula de vencimiento anticipado si el comprador vende la empresa durante el periodo de earn-out."}
  ]'::jsonb,
  E'<article class="blog-post-content">\n\n<p class="text-lg leading-relaxed mb-8"><strong>Un earn-out es un mecanismo contractual utilizado en operaciones de <a href="/recursos/blog/fusiones-y-adquisiciones">compraventa de empresas (M&amp;A)</a></strong> mediante el cual una parte del precio de compra se condiciona al cumplimiento de determinados objetivos de rendimiento de la empresa adquirida durante un periodo posterior al cierre. Es, en esencia, un <strong>pago variable vinculado a resultados futuros</strong>.</p>\n\n<blockquote class="border-l-4 border-black pl-6 my-8 italic text-gray-700">\n<p>«El earn-out es una herramienta poderosa para cerrar operaciones que de otra forma no se cerrarían. Pero también es una fuente inagotable de conflictos si no se redacta con precisión quirúrgica. En nuestra experiencia, el 60% de las disputas post-cierre en M&amp;A mid-market tienen que ver con la interpretación de cláusulas de earn-out.»</p>\n<footer class="mt-2 not-italic font-semibold text-gray-900">— Samuel Navarro, fundador de Capittal Transacciones</footer>\n</blockquote>\n\n<div class="bg-gray-50 border border-gray-200 rounded-lg p-6 my-8 text-center">\n<p class="text-4xl font-bold text-black mb-2">30–40%</p>\n<p class="text-gray-600">Porcentaje de operaciones mid-market en Europa que incluyen algún componente de earn-out, según el <em>CMS European M&amp;A Study 2024</em>.</p>\n</div>\n\n<h2 class="text-2xl font-bold mt-12 mb-6">Por qué se utiliza un earn-out</h2>\n\n<p>El earn-out resuelve uno de los problemas más frecuentes en M&amp;A: la <strong>brecha de <a href="/recursos/blog/como-se-valora-una-empresa-claves-para-entenderlo-incluye-ejemplo-practico">valoración</a> entre comprador y vendedor</strong> (<em>valuation gap</em>). El vendedor cree que su empresa vale más de lo que el comprador está dispuesto a pagar al cierre. El earn-out permite que ambas partes compartan el riesgo:</p>\n\n<ul class="list-disc pl-6 my-4 space-y-2">\n<li>El <strong>vendedor</strong> acepta un precio al cierre menor, pero con la posibilidad de cobrar más si la empresa cumple objetivos.</li>\n<li>El <strong>comprador</strong> paga un precio al cierre menor, reduciendo su riesgo, y solo paga más si los resultados confirman las proyecciones del vendedor.</li>\n</ul>\n\n<h3 class="text-xl font-semibold mt-8 mb-4">Situaciones típicas donde se utiliza earn-out</h3>\n\n<div class="overflow-x-auto my-6">\n<table class="w-full border-collapse border border-gray-300 text-sm">\n<thead>\n<tr class="bg-gray-100">\n<th class="border border-gray-300 px-4 py-3 text-left font-semibold">Situación</th>\n<th class="border border-gray-300 px-4 py-3 text-left font-semibold">Ejemplo</th>\n<th class="border border-gray-300 px-4 py-3 text-left font-semibold">Por qué earn-out</th>\n</tr>\n</thead>\n<tbody>\n<tr><td class="border border-gray-300 px-4 py-3">Brecha de valoración</td><td class="border border-gray-300 px-4 py-3">Vendedor pide 12M€, comprador ofrece 9M€</td><td class="border border-gray-300 px-4 py-3">3M€ adicionales si <a href="/recursos/blog/que-es-ebitda">EBITDA</a> &gt; 2M€ en 2 años</td></tr>\n<tr class="bg-gray-50"><td class="border border-gray-300 px-4 py-3">Empresa en crecimiento</td><td class="border border-gray-300 px-4 py-3">Start-up con alto crecimiento pero EBITDA bajo</td><td class="border border-gray-300 px-4 py-3">Pago adicional si ingresos superan hitos</td></tr>\n<tr><td class="border border-gray-300 px-4 py-3">Dependencia del fundador</td><td class="border border-gray-300 px-4 py-3">El 70% de las ventas dependen del fundador</td><td class="border border-gray-300 px-4 py-3">Earn-out vinculado a retención de clientes</td></tr>\n<tr class="bg-gray-50"><td class="border border-gray-300 px-4 py-3">Incertidumbre sectorial</td><td class="border border-gray-300 px-4 py-3">Sector regulado con cambio normativo pendiente</td><td class="border border-gray-300 px-4 py-3">Earn-out si la regulación no impacta negativamente</td></tr>\n<tr><td class="border border-gray-300 px-4 py-3">Hallazgos en <a href="/recursos/blog/que-es-due-diligence">due diligence</a></td><td class="border border-gray-300 px-4 py-3">Riesgo fiscal o laboral no totalmente cuantificable</td><td class="border border-gray-300 px-4 py-3">Earn-out como mecanismo de ajuste de precio</td></tr>\n</tbody>\n</table>\n</div>\n\n<h2 class="text-2xl font-bold mt-12 mb-6">Estructura típica de un earn-out</h2>\n\n<h3 class="text-xl font-semibold mt-8 mb-4">Componentes del precio con earn-out</h3>\n\n<div class="bg-gray-50 border border-gray-200 rounded-lg p-6 my-6">\n<p class="text-center font-mono text-lg font-bold mb-4">Precio total = Precio al cierre (fijo) + Earn-out (variable)</p>\n</div>\n\n<p>En el mid-market español, la estructura típica es:</p>\n<ul class="list-disc pl-6 my-4 space-y-2">\n<li><strong>Precio al cierre:</strong> 60–80% del precio total estimado</li>\n<li><strong>Earn-out:</strong> 20–40% del precio total estimado</li>\n<li><strong>Periodo:</strong> 1 a 3 años post-cierre (lo más habitual: 2 años)</li>\n<li><strong>Métricas:</strong> <a href="/recursos/blog/que-es-ebitda">EBITDA</a>, facturación, margen bruto, retención de clientes o KPIs específicos</li>\n</ul>\n\n<h3 class="text-xl font-semibold mt-8 mb-4">Ejemplo numérico</h3>\n\n<p>Empresa con EBITDA de 2M EUR. El vendedor pide 6x = 12M EUR. El comprador ofrece 5x = 10M EUR al cierre.</p>\n\n<p class="font-semibold mt-4 mb-2">Acuerdo con earn-out:</p>\n<ul class="list-disc pl-6 my-4 space-y-2">\n<li><strong>Precio al cierre:</strong> 10M EUR</li>\n<li><strong>Earn-out:</strong> Hasta 2M EUR adicionales, pagaderos en función de:\n  <ul class="list-disc pl-6 mt-2 space-y-1">\n  <li>Si EBITDA año 1 ≥ 2,2M EUR → pago de 1M EUR</li>\n  <li>Si EBITDA año 2 ≥ 2,4M EUR → pago de 1M EUR adicional</li>\n  </ul>\n</li>\n<li><strong>Precio total potencial:</strong> 12M EUR (alineado con la expectativa del vendedor)</li>\n</ul>\n\n<h2 class="text-2xl font-bold mt-12 mb-6">Cláusulas clave del earn-out</h2>\n\n<p>La redacción de las cláusulas de earn-out es crítica. <strong>Un earn-out mal redactado es una invitación al litigio.</strong> Las cláusulas principales a negociar son:</p>\n\n<div class="overflow-x-auto my-6">\n<table class="w-full border-collapse border border-gray-300 text-sm">\n<thead>\n<tr class="bg-gray-100">\n<th class="border border-gray-300 px-4 py-3 text-left font-semibold">Cláusula</th>\n<th class="border border-gray-300 px-4 py-3 text-left font-semibold">Qué regula</th>\n<th class="border border-gray-300 px-4 py-3 text-left font-semibold">Punto crítico</th>\n</tr>\n</thead>\n<tbody>\n<tr><td class="border border-gray-300 px-4 py-3">Métrica de referencia</td><td class="border border-gray-300 px-4 py-3">EBITDA, facturación, EBIT, margen</td><td class="border border-gray-300 px-4 py-3">Definición precisa, incluyendo ajustes</td></tr>\n<tr class="bg-gray-50"><td class="border border-gray-300 px-4 py-3">Periodo de medición</td><td class="border border-gray-300 px-4 py-3">1, 2 o 3 años; anual o acumulado</td><td class="border border-gray-300 px-4 py-3">Anual vs. acumulado cambia el riesgo</td></tr>\n<tr><td class="border border-gray-300 px-4 py-3">Principios contables</td><td class="border border-gray-300 px-4 py-3">NIIF, PGC, criterios consistentes</td><td class="border border-gray-300 px-4 py-3">Evitar que el comprador cambie criterios</td></tr>\n<tr class="bg-gray-50"><td class="border border-gray-300 px-4 py-3">Gestión del negocio</td><td class="border border-gray-300 px-4 py-3">Grado de autonomía del vendedor</td><td class="border border-gray-300 px-4 py-3">Restricciones a decisiones del comprador</td></tr>\n<tr><td class="border border-gray-300 px-4 py-3">Protección anti-manipulación</td><td class="border border-gray-300 px-4 py-3">Que el comprador no sabotee los objetivos</td><td class="border border-gray-300 px-4 py-3">Cláusulas de buena fe y <em>good leaver</em></td></tr>\n<tr class="bg-gray-50"><td class="border border-gray-300 px-4 py-3">Mecanismo de revisión</td><td class="border border-gray-300 px-4 py-3">Auditor independiente, procedimiento</td><td class="border border-gray-300 px-4 py-3">Derecho del vendedor a auditar los números</td></tr>\n<tr><td class="border border-gray-300 px-4 py-3">Aceleración de pago</td><td class="border border-gray-300 px-4 py-3">Venta de la empresa durante el earn-out</td><td class="border border-gray-300 px-4 py-3">El vendedor cobra el earn-out máximo si se revende</td></tr>\n<tr class="bg-gray-50"><td class="border border-gray-300 px-4 py-3">Fiscalidad</td><td class="border border-gray-300 px-4 py-3">Tratamiento fiscal del earn-out</td><td class="border border-gray-300 px-4 py-3">Renta del trabajo vs. ganancia patrimonial</td></tr>\n</tbody>\n</table>\n</div>\n\n<blockquote class="border-l-4 border-black pl-6 my-8 italic text-gray-700">\n<p>«La cláusula más importante del earn-out es la de gestión del negocio post-cierre. Si el comprador puede tomar decisiones que afecten al EBITDA (trasladar empleados, reasignar clientes, cargar costes corporativos), el vendedor pierde el control sobre su earn-out. Hay que negociar perímetros claros y protecciones anti-manipulación.»</p>\n<footer class="mt-2 not-italic font-semibold text-gray-900">— Samuel Navarro, Capittal Transacciones</footer>\n</blockquote>\n\n<h2 class="text-2xl font-bold mt-12 mb-6">Riesgos del earn-out para cada parte</h2>\n\n<h3 class="text-xl font-semibold mt-8 mb-4">Riesgos para el vendedor</h3>\n<ul class="list-disc pl-6 my-4 space-y-3">\n<li><strong>Pérdida de control.</strong> Tras el cierre, el comprador dirige la empresa. Puede tomar decisiones operativas que perjudiquen el earn-out (reorganizaciones, cambios de precios, reasignación de personal).</li>\n<li><strong>Manipulación contable.</strong> El comprador puede cargar costes corporativos, diferir ingresos o acelerar gastos para reducir el EBITDA durante el periodo de earn-out.</li>\n<li><strong>Cambio de perímetro.</strong> Si el comprador fusiona la empresa con otra, traslada actividades o modifica la estructura, la métrica de earn-out pierde sentido.</li>\n<li><strong>Riesgo de impago.</strong> Si el comprador tiene dificultades financieras tras el cierre, puede no poder pagar el earn-out. Importante negociar garantías (aval, escrow, garantía de casa matriz).</li>\n</ul>\n\n<h3 class="text-xl font-semibold mt-8 mb-4">Riesgos para el comprador</h3>\n<ul class="list-disc pl-6 my-4 space-y-3">\n<li><strong>Gestión defensiva del vendedor.</strong> Si el vendedor permanece como directivo durante el earn-out, puede tomar decisiones cortoplacistas (inflar ventas, diferir inversiones) para maximizar su earn-out a costa del largo plazo.</li>\n<li><strong>Conflictos de integración.</strong> El earn-out limita la capacidad del comprador de integrar plenamente la empresa adquirida durante el periodo de medición.</li>\n<li><strong>Precio final superior al valor.</strong> Si los objetivos se cumplen por factores exógenos (mejora del mercado, tipo de cambio), el comprador puede acabar pagando más de lo que la empresa realmente vale por méritos propios.</li>\n</ul>\n\n<h2 class="text-2xl font-bold mt-12 mb-6">Tratamiento fiscal del earn-out en España</h2>\n\n<p>La calificación fiscal del earn-out es una cuestión relevante:</p>\n<ul class="list-disc pl-6 my-4 space-y-3">\n<li><strong>Si el vendedor NO permanece en la empresa:</strong> El earn-out tributa como <strong>ganancia patrimonial</strong>, al tipo del ahorro (19–30% en IRPF para persona física), como un complemento del precio de <a href="/recursos/blog/vender-mi-empresa">venta</a>.</li>\n<li><strong>Si el vendedor permanece como directivo:</strong> La Agencia Tributaria puede recalificar parte del earn-out como <strong>rendimientos del trabajo</strong>, sujetos a tipos marginales del IRPF (hasta el 47–54% según comunidad autónoma). Es fundamental que el earn-out esté vinculado al precio de venta y no a la prestación de servicios.</li>\n</ul>\n\n<h2 class="text-2xl font-bold mt-12 mb-6">Preguntas frecuentes sobre earn-out</h2>\n\n<div class="space-y-6 my-8">\n<div class="bg-gray-50 rounded-lg p-6">\n<h3 class="font-semibold text-lg mb-2">¿Qué porcentaje del precio suele ser earn-out?</h3>\n<p>En el mid-market español y europeo, el earn-out representa típicamente entre el 10% y el 30% del precio total de la operación. Porcentajes superiores al 40% son inusuales y suelen indicar un nivel de incertidumbre muy alto sobre el negocio. Según el <em>CMS European M&amp;A Study 2024</em>, la media se sitúa en torno al 20–25% del precio total.</p>\n</div>\n\n<div class="bg-gray-50 rounded-lg p-6">\n<h3 class="font-semibold text-lg mb-2">¿Es mejor EBITDA o facturación como métrica de earn-out?</h3>\n<p>Depende del contexto. El <a href="/recursos/blog/que-es-ebitda">EBITDA</a> es la métrica más habitual porque refleja la rentabilidad real, pero es más susceptible de manipulación (el comprador puede cargar costes corporativos). La facturación es más transparente y difícil de manipular, pero no refleja la rentabilidad. En empresas en fase de crecimiento (start-ups, scale-ups), la facturación suele ser más apropiada. En empresas maduras, el EBITDA es el estándar.</p>\n</div>\n\n<div class="bg-gray-50 rounded-lg p-6">\n<h3 class="font-semibold text-lg mb-2">¿Puedo negarme a aceptar un earn-out?</h3>\n<p>Sí, el vendedor puede rechazar una estructura con earn-out. Sin embargo, en la práctica, rechazar cualquier componente variable puede significar aceptar un precio al cierre menor o incluso perder al comprador. La clave es negociar las cláusulas del earn-out para proteger tus intereses, no rechazarlo frontalmente si la oferta global es atractiva.</p>\n</div>\n\n<div class="bg-gray-50 rounded-lg p-6">\n<h3 class="font-semibold text-lg mb-2">¿Qué pasa si el comprador no paga el earn-out?</h3>\n<p>Si los objetivos se cumplen y el comprador no paga, el vendedor tiene acción legal para reclamar. Pero litigar es costoso e incierto. Por eso es fundamental negociar garantías de pago: depósito en escrow, aval bancario, garantía de la sociedad matriz del comprador, o cláusula de vencimiento anticipado si el comprador vende la empresa durante el periodo de earn-out.</p>\n</div>\n</div>\n\n<h2 class="text-2xl font-bold mt-12 mb-6">Fuentes y referencias</h2>\n<ul class="list-disc pl-6 my-4 space-y-2 text-sm text-gray-600">\n<li>CMS. <em>European M&amp;A Study 2024</em>.</li>\n<li>Argos Index, Epsilon Research. <em>Mid-Market Valuation Multiples, Q4 2024</em>.</li>\n<li>SRS Advogados / Lexology. <em>Earn-out Mechanisms in M&amp;A: Practical Issues and Case Law</em>, 2024.</li>\n<li>AEAT. Consultas vinculantes sobre tributación de earn-outs (V0472-22, V1839-23).</li>\n<li>Ley 35/2006, del IRPF, arts. 33–37 (ganancias patrimoniales).</li>\n</ul>\n\n<p class="text-sm text-gray-500 mt-8 mb-6"><em>Última actualización: marzo 2026</em></p>\n\n<div class="bg-black text-white rounded-lg p-8 mt-12">\n<h3 class="text-xl font-bold mb-3">¿Necesitas estructurar un earn-out en tu operación?</h3>\n<p class="mb-4 text-gray-300">En Capittal Transacciones asesoramos en la negociación de cláusulas de earn-out que protejan los intereses del vendedor.</p>\n<a href="/contacto" class="inline-block bg-white text-black font-semibold px-6 py-3 rounded-lg hover:bg-gray-100 transition-colors">Contacta con nuestro equipo</a>\n</div>\n\n</article>'
);